const body = ($json && typeof $json === 'object') ? ($json.body ?? $json) : {};

const REQUIRED = ['artifact_name', 'current_stage', 'artifact_text'];
const ALL = ['artifact_name','source','current_stage','decision_needed','risk_level','main_concern','artifact_text'];
const ALLOWED_STAGES = [
  'Concept',
  'Draft Workflow',
  'Operational Prototype',
  'Pre-Production Spec',
  'Production Candidate',
];

const normalized = {};
for (const key of ALL) {
  const v = body?.[key];
  if (typeof v === 'string') normalized[key] = v.trim();
  else if (v === null || v === undefined) normalized[key] = '';
  else normalized[key] = String(v).trim();
}

const missing_fields = [];
for (const key of REQUIRED) {
  if (!normalized[key]) missing_fields.push(key);
}

const invalid_fields = [];
if (normalized.current_stage && !ALLOWED_STAGES.includes(normalized.current_stage)) invalid_fields.push('current_stage');

const limit = 25000;
if (normalized.artifact_text && normalized.artifact_text.length > limit) invalid_fields.push('artifact_text');

if (missing_fields.length || invalid_fields.length) {
  const tooLarge = invalid_fields.includes('artifact_text') && (normalized.artifact_text.length > limit);
  return [{
    json: {
      status: 'error',
      message: tooLarge ? 'Payload too large' : 'Invalid input',
      missing_fields,
      invalid_fields,
      http_code: 400,
    },
  }];
}

return [{ json: { status: 'pass', ...normalized } }];

const res = $json;
const requiredKeys = ($items('Build OpenAI Request')[0]?.json?.requiredKeys) || [];

const sanitizeError = (err) => {
  if (!err || typeof err !== 'object') return err;
  return { name: err.name, code: err.code, status: err.status, message: err.message };
};

if (res && typeof res === 'object' && res.error) {
  return [{ json: { status:'error', message:'OpenAI request failed', missing_fields: [], invalid_fields: ['openai_request'], details: sanitizeError(res.error), http_code: 502 } }];
}

const statusCode = typeof res.statusCode === 'number' ? res.statusCode : null;
const body = res.body ?? res;

if (statusCode && statusCode >= 400) {
  return [{ json: { status:'error', message:'OpenAI request failed', missing_fields: [], invalid_fields: ['openai_request'], details: body, http_code: 502 } }];
}

const reply = body?.choices?.[0]?.message?.content;
if (typeof reply !== 'string' || !reply.trim()) {
  return [{ json: { status:'error', message:'No assistant reply found in OpenAI response', missing_fields: [], invalid_fields: ['openai_output'], details: body, http_code: 502 } }];
}

let parsed;
try {
  parsed = JSON.parse(reply);
} catch (e) {
  return [{ json: { status:'error', message:'Invalid AI output', missing_fields: [], invalid_fields: ['openai_output'], details: { parse_error: String(e?.message || e), raw: reply.slice(0, 5000) }, http_code: 502 } }];
}

const missing = [];
for (const k of requiredKeys) {
  if (!Object.prototype.hasOwnProperty.call(parsed, k)) missing.push(k);
}

if (missing.length) {
  return [{ json: { status:'error', message:'Invalid AI output', missing_fields: missing, invalid_fields: ['openai_output'], details: { missing_keys: missing }, http_code: 502 } }];
}

// Prepare save payload
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const ts = `${now.getFullYear()}-${pad(now.getMonth()+1)}-${pad(now.getDate())}T${pad(now.getHours())}${pad(now.getMinutes())}`;

const artifactName = String($items('Build OpenAI Request')[0]?.json?.artifact_name || 'Artifact').trim() || 'Artifact';
const safeName = artifactName.replace(/[\\/:*?"<>|]+/g, '-').replace(/\s+/g, ' ').trim();

return [{
  json: {
    status: 'pass',
    artifact_name: artifactName,
    reviewed_at: now.toISOString(),
    file_name: `${safeName} - Review - ${ts}.json`,
    file_content: JSON.stringify(parsed, null, 2),
  },
}];

const drive = $json;
const ctx = $items('Extract + Validate AI JSON')[0]?.json;

if (!ctx || ctx.status !== 'pass') {
  return [{ json: { status:'error', message:'Internal error (missing AI context)', missing_fields: [], invalid_fields: ['internal'], http_code: 500 } }];
}

if (drive && typeof drive === 'object' && drive.error) {
  return [{ json: { status:'error', message:'Drive save failed', missing_fields: [], invalid_fields: ['drive'], details: drive.error, http_code: 502 } }];
}

if (!drive || typeof drive !== 'object' || typeof drive.id !== 'string') {
  return [{ json: { status:'error', message:'Drive save failed', missing_fields: [], invalid_fields: ['drive'], details: drive ?? null, http_code: 502 } }];
}

return [{
  json: {
    status: 'success',
    artifact_name: ctx.artifact_name,
    review_file_name: ctx.file_name,
    drive_file_id: drive.id,
    reviewed_at: ctx.reviewed_at,
    http_code: 200,
  },
}];
